import React, { useEffect, useState } from "react";
import Header from "./Header";
import NotFound from "./NotFound";
import { Route, Switch, useHistory, useParams } from "react-router-dom";
import Decks from "./Components/Decks";
import CreateDeckBtn from "./Components/CreateDeckBtn";
import { listDecks } from "../utils/api/index.js";
import Study from "./Components/Study";
import { deleteDeck } from "../utils/api/index.js";
import StudyNav from "./Components/StudyNav";
import CreateDeck from "./Components/CreateDeck";
import CreateNav from "./Components/CreateNav";
import DeckView from "./Components/DeckView";
import DeckViewNav from "./Components/DeckViewNav";
import EditDeckNav from "./Components/EditDeckNav";
import EditDeck from "./Components/EditDeck";
import AddCardNav from "./Components/AddCardNav";
import AddCard from "./Components/AddCard";
import EditCardNav from "./Components/EditCardNav";
import EditCard from "./Components/EditCard";
import { createDeck } from "../utils/api/index.js";

function Layout() {
  const [decks, setDecks] = useState([]);
  const history = useHistory();

  useEffect(() => {
    async function waitDecks() {
      await loadDecks();
    }
    waitDecks();
  }, [handleCreateDeckBtn]);

  // LOAD DECKS
  async function loadDecks() {
    try {
      const deckData = await listDecks();
      setDecks(deckData);
    } catch (err) {
      console.log(err);
    }
  }

  // Creates a new deck with the information that was inputed.
  async function handleCreateDeckBtn(e) {
    e.preventDefault();
    const title = document.getElementById("deckTitleInput").value;
    const text = document.getElementById("deckTextInput").value;
    const obj = { name: title, description: text };
    const result = await createDeck(obj);
    history.push(`/decks/${result.id}`)
  }

  // HANDLE DELETE DECK --- Not working properly with card count after clicking...
  async function handleDeleteDeck(id) {
    await deleteDeck(id);
    await loadDecks();
  }

  // RETURN LAYOUT
  return (
    <div>
      <Header />
      <div className="container">
        <Switch>
          <Route exact path="/">
            <CreateDeckBtn />
            <Decks
              handleDeleteDeck={handleDeleteDeck}
              decks={decks}
            />
          </Route>
          <Route path="/decks/:deckId/cards/:cardId/edit">
            <EditCardNav />
            <EditCard />
          </Route>
          <Route path="/decks/:deckId/cards/new">
            <AddCardNav />
            <AddCard />
          </Route>
          <Route path="/decks/:deckId/study">
            <StudyNav />
            <Study decks={decks} />
          </Route>
          <Route path="/decks/:deckId/edit">
            <EditDeckNav />
            <EditDeck loadDecks={loadDecks} />
          </Route>
          <Route path="/decks/new">
            <CreateNav />
            <CreateDeck handleCreateDeckBtn={handleCreateDeckBtn} />
          </Route>
          <Route path="/decks/:deckId">
            <DeckViewNav />
            <DeckView handleDeleteDeck={handleDeleteDeck} decks={decks} />
          </Route>
          <Route>
            <NotFound />
          </Route>
        </Switch>
      </div>
    </div>
  );
}

export default Layout;
